- 动态实现

```c
/*（线性表）顺序表的实现--动态分配*/
#include <stdio.h>
#include <stdlib.h>
#define OK 1
#define ERROR 0
#define InitSize 5
//建表
typedef struct {
    int *data;//指向动态分配的数组的指针（指向数组第一个元素）
    int MaxSize;//最大容量
    int length;//当前表长
}SqList;
//初始化
int InitList(SqList *L){
    L->data = (int*) malloc(InitSize*sizeof(int));
    L->MaxSize = InitSize;
    L->length = 0;
}
//扩大容量
int Increase(SqList *L,int len){//len是要扩大多少
    int *p;
    p=L->data;
    L->data = (int *) malloc((InitSize+len)*sizeof(int));
    for(int i=1;i<=L->length;i++){
        p[i-1]=L->data[i-1];
    }
    L->MaxSize = InitSize + len;
    free(p);
    return OK;
}
//输出当前最大容量
int GetSize(SqList L){
    printf("当前最大容量为:%d\n",L.MaxSize);
    return OK;
}
//按位查找,第i个元素是啥
int GetList(SqList L,int i,int *e){
    if(i<1 || i>L.length){
        return ERROR;
    }
    *e = L.data[i-1];//思考为啥是*e
    printf("第%d位是%d\n",i,*e);
    return OK;
}
//按值查找
int LocateList(SqList L,int e){
    int i;
    for(i=1;i<=L.length;i++){
        if(e == L.data[i-1]){
            break;
        }
    }
    return i;
}
//插入
int Insert(SqList *L,int i,int e){
    if(i<1 || i>L->length+1){
        return ERROR;
    }
    if(L->length==L->MaxSize){
        return ERROR;
    }
    if(i<=L->length) {
        for (int j = L->length; j >= i; j--) {
            L->data[j] = L->data[j-1];
        }
    }
    L->data[i-1]=e;
    L->length++;
    return OK;
}
//删除
int Delete(SqList *L,int i,int *e){
    if(i<1 || i>L->length){
        return ERROR;
    }
    if(L->length==0){
        return ERROR;
    }
    if(i<L->length){
        for(int j=i;j<=L->length;j++){
            L->data[j-1]=L->data[j];
        }
        *e = L->data[i-1];
        L->length--;
        return OK;
    }
}
//输出
int Print(SqList L){
    if(L.length==0){
        return ERROR;
    }
    for(int i=1;i<=L.length;i++){
        printf("%d\t",L.data[i-1]);
    }
    printf("\n");
    return OK;
}
```

```c
